export const ICON_MAP: Record<string, string> = Object.fromEntries(
  ICONS.map((i) => [i.name, i.body])
)

export function hasIcon(name?: string): boolean {
  return !!name && Object.prototype.hasOwnProperty.call(ICON_MAP, name)
}
